19: package org.apache.flink.streaming.api.windowing.triggers;
20: 
21: import org.apache.flink.annotation.PublicEvolving;
22: import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
23: 
24: /**
25:  * A {@link Trigger} that fires once the watermark passes the end of the window to which a pane
26:  * belongs.
27:  *
28:  * @see org.apache.flink.streaming.api.watermark.Watermark
29:  */
30: @PublicEvolving
31: public class EventTimeTrigger extends Trigger<Object, TimeWindow> {
32:     private static final long serialVersionUID = 1L;
33: 
34:     private EventTimeTrigger() {}
35: 
36:     @Override
37:     public TriggerResult onElement(
38:             Object element, long timestamp, TimeWindow window, TriggerContext ctx)
39:             throws Exception {
40:         if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
41:             // if the watermark is already past the window fire immediately
42:             return TriggerResult.FIRE;
43:         } else {
44:             ctx.registerEventTimeTimer(window.maxTimestamp());
45:             return TriggerResult.CONTINUE;
46:         }
47:     }
48: 
49:     @Override
50:     public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
51:         return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
52:     }
53: 
54:     @Override
55:     public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
56:             throws Exception {
57:         return TriggerResult.CONTINUE;
58:     }
59: 
60:     @Override
61:     public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
62:         ctx.deleteEventTimeTimer(window.maxTimestamp());
63:     }
64: 
65:     @Override
66:     public boolean canMerge() {
67:         return true;
68:     }
69: 
70:     @Override
71:     public void onMerge(TimeWindow window, OnMergeContext ctx) {
72:         // only register a timer if the watermark is not yet past the end of the merged window
73:         // this is in line with the logic in onElement(). If the watermark is past the end of
74:         // the window onElement() will fire and setting a timer here would fire the window twice.
75:         long windowMaxTimestamp = window.maxTimestamp();
76:         if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
77:             ctx.registerEventTimeTimer(windowMaxTimestamp);
78:         }
79:     }
80: 
81:     @Override
82:     public String toString() {
83:         return "EventTimeTrigger()";
84:     }
85: 
86:     /**
87:      * Creates an event-time trigger that fires once the watermark passes the end of the window.
88:      *
89:      * <p>Once the trigger fires all elements are discarded. Elements that arrive late immediately
90:      * trigger window evaluation with just this one element.
91:      */
92:     public static EventTimeTrigger create() {
93:         return new EventTimeTrigger();
94:     }
95: }
