    25→import org.apache.flink.streaming.api.windowing.triggers.Trigger;
    26→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    27→
    28→import java.time.LocalTime;
    29→import java.time.ZoneId;
    30→import java.time.ZonedDateTime;
    31→import java.util.Collection;
    32→import java.util.Collections;
    33→import java.util.HashMap;
    34→import java.util.Map;
    35→
    36→/**
    37→ * A {@link WindowAssigner} that assigns elements to trading session windows based on market
    38→ * session boundaries. Windows are defined by market open and close times in a specific time zone.
    39→ *
    40→ * <p>For example, for NYSE (09:30-16:00 ET), elements with timestamps within that period would be
    41→ * assigned to a window representing that trading day's session.
    42→ *
    43→ * <p>This assigner supports multiple markets with different session times via the
    44→ * {@link TradingSessionExtractor} mechanism.
    45→ *
    46→ * <p>This is a {@link MergingWindowAssigner}, so overlapping session windows will be merged
    47→ * automatically.
    48→ */
    49→@PublicEvolving
    50→public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    51→    private static final long serialVersionUID = 1L;
    52→
    53→    private final String marketId;
    54→    private final ZoneId timezone;
    55→    private final LocalTime sessionOpen;
    56→    private final LocalTime sessionClose;
    57→
    58→    /**
    59→     * Creates a new PricingSessionWindow for a single market.
    60→     *
    61→     * @param marketId The market identifier (e.g., "NYSE", "LSE")
    62→     * @param timezone The timezone in which the market operates
    63→     * @param sessionOpen The market session open time (local time)
    64→     * @param sessionClose The market session close time (local time)
    65→     */
    66→    protected PricingSessionWindow(
    67→            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
    68→        if (marketId == null || timezone == null || sessionOpen == null || sessionClose == null) {
    69→            throw new IllegalArgumentException(
    70→                    "marketId, timezone, sessionOpen, and sessionClose must not be null");
    71→        }
    72→        if (!sessionClose.isAfter(sessionOpen)) {
    73→            throw new IllegalArgumentException("sessionClose must be after sessionOpen");
    74→        }
    75→
    76→        this.marketId = marketId;
    77→        this.timezone = timezone;
    78→        this.sessionOpen = sessionOpen;
    79→        this.sessionClose = sessionClose;
    80→    }
    81→
    82→    @Override
    83→    public Collection<TimeWindow> assignWindows(
    84→            Object element, long timestamp, WindowAssignerContext context) {
    85→        // Convert the timestamp to the market's timezone
    86→        ZonedDateTime eventTime =
    87→                ZonedDateTime.ofInstant(
    88→                        java.time.Instant.ofEpochMilli(timestamp),
    89→                        timezone);
    90→
    91→        // Get the date in the market's timezone
    92→        ZonedDateTime sessionStartDateTime =
    93→                eventTime.toLocalDate().atTime(sessionOpen).atZone(timezone);
    94→        ZonedDateTime sessionEndDateTime =
    95→                eventTime.toLocalDate().atTime(sessionClose).atZone(timezone);
    96→
    97→        // Handle overnight sessions: if event time is before session open today,
    98→        // it might belong to yesterday's session
    99→        if (eventTime.isBefore(sessionStartDateTime)) {
   100→            sessionStartDateTime = sessionStartDateTime.minusDays(1);
   101→            sessionEndDateTime = sessionEndDateTime.minusDays(1);
   102→        }
   103→
   104→        // Also handle events after session close: they belong to next session if still within range
   105→        // For intra-day sessions, events after close go to next session
   106→        if (eventTime.isAfter(sessionEndDateTime)) {
   107→            sessionStartDateTime = sessionStartDateTime.plusDays(1);
   108→            sessionEndDateTime = sessionEndDateTime.plusDays(1);
   109→        }
   110→
   111→        long windowStart = sessionStartDateTime.toInstant().toEpochMilli();
   112→        long windowEnd = sessionEndDateTime.toInstant().toEpochMilli();
   113→
   114→        return Collections.singletonList(new TimeWindow(windowStart, windowEnd));
   115→    }
   116→
   117→    @Override
   118→    public Trigger<Object, TimeWindow> getDefaultTrigger() {
   119→        return EventTimeTrigger.create();
   120→    }
   121→
   122→    @Override
   123→    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
   124→        return new TimeWindow.Serializer();
   125→    }
   126→
   127→    @Override
   128→    public boolean isEventTime() {
   129→        return true;
   130→    }
   131→
   132→    /** Merge overlapping {@link TimeWindow}s. */
   133→    @Override
   134→    public void mergeWindows(
   135→            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
   136→        TimeWindow.mergeWindows(windows, c);
   137→    }
   138→
   139→    @Override
   140→    public String toString() {
   141→        return "PricingSessionWindow(market="
   142→                + marketId
   143→                + ", open="
   144→                + sessionOpen
   145→                + ", close="
   146→                + sessionClose
   147→                + ", tz="
   148→                + timezone
   149→                + ")";
   150→    }
   151→
   152→    /**
   153→     * Creates a new {@code PricingSessionWindow} for a specific market with defined trading hours.
   154→     *
   155→     * @param marketId The market identifier (e.g., "NYSE")
   156→     * @param timezone The timezone in which the market operates
   157→     * @param open The market session open time (local time)
   158→     * @param close The market session close time (local time)
   159→     * @return A new PricingSessionWindow instance
   160→     */
   161→    public static PricingSessionWindow forMarket(
   162→            String marketId, ZoneId timezone, LocalTime open, LocalTime close) {
   163→        return new PricingSessionWindow(marketId, timezone, open, close);
   164→    }
